/**
 * Task report module.
 *
 * Formats a list of tasks into a plain-text report: a title header, one line
 * per task, an optional summary section, and a footer with totals. The public
 * surface is `formatReport` and the option/type exports; everything else is
 * internal machinery.
 */

export interface Task {
  title: string;
  done: boolean;
  hours: number;
}

export interface ReportInput {
  title: string;
  tasks: Task[];
}

export interface ReportOptions {
  separator?: string;
  bullet?: string;
  sections?: string[];
  theme?: string;
  locale?: string;
  outputFormat?: "text";
}

const DEFAULT_OPTIONS: Required<ReportOptions> = {
  separator: "=",
  bullet: "-",
  sections: ["header", "tasks", "footer"],
  theme: "default",
  locale: "en",
  outputFormat: "text",
};

const THEMES = {
  default: {
    doneMarker: "[x]",
    openMarker: "[ ]",
  },
};

const MESSAGES = {
  en: {
    done: "done",
    total: "total",
    doneLabel: "Done",
    openLabel: "Open",
    hoursLabel: "Hours",
  },
};

interface Context {
  input: ReportInput;
  separator: string;
  bullet: string;
  messages: typeof MESSAGES.en;
}

function formatHours(hours: number): string {
  return `${hours}h`;
}

function renderHeader(ctx: Context): string[] {
  const { title } = ctx.input;
  return [title, ctx.separator.repeat(title.length)];
}

function renderTasks(ctx: Context): string[] {
  const theme = THEMES.default;
  return ctx.input.tasks.map((task) => {
    const marker = task.done ? theme.doneMarker : theme.openMarker;
    return `${ctx.bullet} ${marker} ${task.title} (${formatHours(task.hours)})`;
  });
}

function renderSummary(ctx: Context): string[] {
  const { tasks } = ctx.input;
  let doneCount = 0;
  let totalHours = 0;
  for (const task of tasks) {
    if (task.done) doneCount += 1;
    totalHours += task.hours;
  }
  const openCount = tasks.length - doneCount;
  return [
    `${ctx.messages.doneLabel}: ${doneCount}`,
    `${ctx.messages.openLabel}: ${openCount}`,
    `${ctx.messages.hoursLabel}: ${formatHours(totalHours)}`,
  ];
}

function renderFooter(ctx: Context): string[] {
  const { tasks } = ctx.input;
  let doneCount = 0;
  let totalHours = 0;
  for (const task of tasks) {
    if (task.done) doneCount += 1;
    totalHours += task.hours;
  }
  return [
    `${doneCount}/${tasks.length} ${ctx.messages.done}, ${formatHours(totalHours)} ${ctx.messages.total}`,
  ];
}

const RENDERERS: Record<string, (ctx: Context) => string[]> = {
  header: renderHeader,
  tasks: renderTasks,
  summary: renderSummary,
  footer: renderFooter,
};

export function formatReport(input: ReportInput, options?: ReportOptions): string {
  const opts = { ...DEFAULT_OPTIONS, ...options };

  const messages = MESSAGES[opts.locale as keyof typeof MESSAGES];
  if (!messages) {
    throw new Error(`no messages for locale: ${opts.locale}`);
  }

  const context: Context = {
    input,
    separator: opts.separator,
    bullet: opts.bullet,
    messages,
  };

  const lines: string[] = [];
  for (const section of opts.sections) {
    const renderer = RENDERERS[section];
    if (!renderer) {
      throw new Error(`no renderer for section: ${section}`);
    }
    lines.push(...renderer(context));
  }

  return lines.join("\n");
}

